// Unit 27 — La Nominalización
// Academic Register & Formal Writing

export default {n:27,lang:"es",srcLang:"en",track:"v2",title:"La Nominalización",sub:"Academic Register & Formal Writing",icon:"🎓",level:"B2.2",color:"#7B5EE8",lessons:[
  {id:"esp27l1",title:"El Hecho de Que",icon:"📝",xp:15,board:true,steps:[
        {type:"intro",title:"El Hecho de Que",desc:"Learn to use noun phrases that turn ideas into subjects and objects. This is the key to sounding academic in Spanish.",goals:["Use el hecho de que in sentences","Form noun phrases with la posibilidad de","Recognize nominalization patterns"]},
        {type:"teach",trg:"el hecho de que",src:"the fact that",pos:"noun",gender:"m",phonetic:"el EH-cho deh keh",note:"Always followed by subjuntivo. Core academic phrase.",example:"A: ¿Por qué rechazaron el proyecto?\nB: El hecho de que no presentaran datos fue decisivo.\nA: ¿Pero tenían la información?\nB: Sí, pero el hecho de que llegaran tarde tampoco ayudó.\nA: Entiendo. Los plazos son importantes.",exampleSrc:"A: Why did they reject the project?\nB: The fact that they didn't present data was decisive.\nA: But did they have the information?\nB: Yes, but the fact that they arrived late didn't help either.\nA: I understand. Deadlines are important.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la posibilidad de",src:"the possibility of",pos:"verb",gender:null,phonetic:"la po-see-bee-lee-DAD deh",note:"Followed by de + infinitive or de que + subjuntivo.",example:"A: ¿Crees que aprobarán la ley?\nB: La posibilidad de que la aprueben es baja.\nA: ¿Y si cambian algunos artículos?\nB: Eso aumentaría la posibilidad de llegar a un acuerdo.\nA: Esperemos que así sea.",exampleSrc:"A: Do you think they'll pass the law?\nB: The possibility of them passing it is low.\nA: What if they change some articles?\nB: That would increase the possibility of reaching an agreement.\nA: Let's hope so.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"el desarrollo de",src:"the development of",pos:"noun",gender:"m",phonetic:"el deh-sa-RRO-yo deh",note:"Noun form of desarrollar. Very common in academic texts.",example:"A: ¿Sobre qué trata tu tesis?\nB: Sobre el desarrollo de nuevas tecnologías educativas.\nA: Suena interesante. ¿Qué has encontrado?\nB: Que el desarrollo de estas herramientas requiere mucha inversión.\nA: ¿Y vale la pena?\nB: Sin duda. El desarrollo de este campo es fundamental.",exampleSrc:"A: What is your thesis about?\nB: About the development of new educational technologies.\nA: That sounds interesting. What have you found?\nB: That the development of these tools requires a lot of investment.\nA: And is it worth it?\nB: Absolutely. The development of this field is fundamental.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la importancia de",src:"the importance of",pos:"verb",gender:null,phonetic:"la im-por-TAN-thya deh",note:"Noun form of importante. Followed by de + noun/infinitive.",example:"A: ¿Qué conclusiones sacaste del estudio?\nB: La importancia de la educación temprana es indiscutible.\nA: ¿Encontraste datos que lo confirmen?\nB: Sí, la importancia de invertir en los primeros años es clara.\nA: ¿Podrías compartir los datos?\nB: Por supuesto, te envío el informe.",exampleSrc:"A: What conclusions did you draw from the study?\nB: The importance of early education is indisputable.\nA: Did you find data to confirm it?\nB: Yes, the importance of investing in the early years is clear.\nA: Could you share the data?\nB: Of course, I'll send you the report.",funFact:"Cognate with English 'importance of'. Spanish and English share many Latin-derived words."},
        {type:"tip",title:"What is Nominalization?",text:"Nominalization turns verbs and adjectives into nouns:\n\ndesarrollar (to develop) → el desarrollo (the development)\nimportante (important) → la importancia (the importance)\nposible (possible) → la posibilidad (the possibility)\n\nThis makes sentences sound more formal and academic.\nCasual: Es importante estudiar.\nFormal: La importancia del estudio es innegable."},
        {type:"teach",trg:"la necesidad de",src:"the need for / the necessity of",pos:"noun",gender:"f",phonetic:"la neh-theh-see-DAD deh",note:"From necesario. Used constantly in formal arguments.",example:"A: ¿Cuál es el problema principal?\nB: La necesidad de reformar el sistema es urgente.\nA: ¿Todos están de acuerdo?\nB: No, pero la necesidad de actuar es evidente.\nA: ¿Qué proponen?\nB: Un plan que responda a la necesidad de modernización.",exampleSrc:"A: What is the main problem?\nB: The need to reform the system is urgent.\nA: Does everyone agree?\nB: No, but the necessity of acting is evident.\nA: What do they propose?\nB: A plan that responds to the need for modernization.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"mc",q:"Complete: ___ de que no hubiera pruebas fue determinante.",opts:["El hecho","La hecho","El facto","Lo hecho"],ans:"El hecho",hint:"This masculine noun phrase means 'the fact'."},
        {type:"mc",q:"Which phrase means 'the development of'?",opts:["La posibilidad de","El desarrollo de","La necesidad de","El proceso de"],ans:"El desarrollo de",hint:"Think of the verb desarrollar turned into a noun."},
        {type:"fb",opts:["importancia","importante","importar","importando"],hint:"The noun form of the adjective meaning 'important'.",s:"La {1} de invertir en educación es clara.",a:"importancia"},
        {type:"fb",opts:["llegaran","llegaron","llegan","llegarán"],hint:"After el hecho de que, use the subjunctive mood.",s:"El hecho de que {1} tarde fue un problema.",a:"llegaran"},
        {type:"mc",q:"La ___ de alcanzar un acuerdo parece remota.",opts:["posibilidad","posible","poder","posiblemente"],ans:"posibilidad",hint:"The noun form of posible, meaning possibility."},
        {type:"match",pairs:[
          {trg:"el hecho de que",src:"the fact that"},
          {trg:"la posibilidad de",src:"the possibility of"},
          {trg:"el desarrollo de",src:"the development of"},
          {trg:"la importancia de",src:"the importance of"},
          {trg:"la necesidad de",src:"the need for"}
        ]},
        {type:"fb",opts:["necesidad","necesario","necesitar","necesitando"],hint:"The noun form of necesario, meaning necessity.",s:"La {1} de reformar las leyes es urgente.",a:"necesidad"},
        {type:"mc",q:"Which sentence sounds most academic?",opts:["Es importante estudiar","La importancia del estudio es innegable","Estudiar importa mucho","Hay que estudiar"],ans:"La importancia del estudio es innegable",hint:"Academic writing prefers noun phrases as subjects."},
        {type:"drag_fill",hint:"Development of strategies requires cooperation.",s:"El {1} de nuevas estrategias requiere la {2} de todos los participantes.",blanks:{"1":"desarrollo","2":"colaboración"},pool:["desarrollo","colaboración","posibilidad","necesidad"]},
        {type:"mc",q:"El hecho de que no ___ suficientes recursos afectó al resultado.",opts:["hubiera","había","hay","habrá"],ans:"hubiera",hint:"After el hecho de que, the verb form changes mood."},
        {type:"fb",opts:["posibilidad","hecho","desarrollo","importancia"],hint:"This noun expresses how likely something is.",s:"El {1} de que aprueben la propuesta es bajo.",a:"posibilidad"}
  ]},
  {id:"esp27l2",title:"Sufijos Nominales",icon:"🔤",xp:15,board:true,steps:[
        {type:"intro",title:"Sufijos Nominales",desc:"Master the suffixes that transform Spanish verbs into nouns. These are the building blocks of academic vocabulary.",goals:["Use -ción/-sión suffixes","Use -miento suffix","Recognize -aje, -ura, -ancia/-encia patterns"]},
        {type:"teach",trg:"la investigación",src:"the investigation / research",pos:"noun",gender:"f",phonetic:"la in-ves-tee-ga-THYON",note:"From investigar. The -ción suffix is the most common nominalizer.",example:"A: ¿En qué área trabajas?\nB: Me dedico a la investigación científica.\nA: ¿Qué tipo de investigación?\nB: La investigación sobre cambio climático.\nA: ¿Y cómo va la investigación?\nB: Bien, publicamos los resultados el mes que viene.",exampleSrc:"A: What area do you work in?\nB: I do scientific research.\nA: What kind of research?\nB: Research on climate change.\nA: And how is the research going?\nB: Well, we publish the results next month.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el conocimiento",src:"the knowledge",pos:"noun",gender:"m",phonetic:"el ko-no-thee-MYEN-to",note:"From conocer + -miento. Very common in academic contexts.",example:"A: ¿Qué se necesita para este puesto?\nB: Se requiere un amplio conocimiento del sector.\nA: ¿Y experiencia práctica?\nB: También, pero el conocimiento teórico es fundamental.\nA: ¿Cómo puedo ampliar mi conocimiento?\nB: Con cursos y lectura especializada.",exampleSrc:"A: What is needed for this position?\nB: Broad knowledge of the sector is required.\nA: And practical experience?\nB: Also, but theoretical knowledge is fundamental.\nA: How can I expand my knowledge?\nB: With courses and specialized reading.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el aprendizaje",src:"the learning (process)",pos:"noun",gender:"m",phonetic:"el a-pren-dee-THA-heh",note:"From aprender + -aje. The suffix -aje creates process nouns.",example:"A: ¿Cómo mejorar la enseñanza?\nB: El aprendizaje debe ser activo, no pasivo.\nA: ¿Qué significa aprendizaje activo?\nB: Que el aprendizaje ocurre haciendo, no solo escuchando.\nA: ¿Hay estudios sobre esto?\nB: Sí, el aprendizaje cooperativo muestra mejores resultados.",exampleSrc:"A: How to improve teaching?\nB: Learning should be active, not passive.\nA: What does active learning mean?\nB: That learning happens by doing, not just listening.\nA: Are there studies on this?\nB: Yes, cooperative learning shows better results.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la estructura",src:"the structure",pos:"noun",gender:"f",phonetic:"la es-truk-TOO-ra",note:"From estructurar. The -ura suffix creates quality/result nouns.",example:"A: ¿Qué opinas del ensayo?\nB: La estructura es clara, pero falta profundidad.\nA: ¿Qué mejorarías de la estructura?\nB: La estructura de los argumentos necesita más lógica.\nA: Entiendo. Trabajaré en eso.\nB: La estructura es la base de un buen texto.",exampleSrc:"A: What do you think of the essay?\nB: The structure is clear, but it lacks depth.\nA: What would you improve about the structure?\nB: The structure of the arguments needs more logic.\nA: I understand. I'll work on that.\nB: Structure is the foundation of a good text.",funFact:"Cognate with English 'structure'. Spanish and English share many Latin-derived words."},
        {type:"tip",title:"Nominalization Suffixes",text:"Common verb-to-noun suffixes:\n\n-ción/-sión: investigar → investigación, decidir → decisión\n-miento: conocer → conocimiento, sentir → sentimiento\n-aje: aprender → aprendizaje, almacenar → almacenaje\n-ura: estructurar → estructura, abrir → abertura\n-ancia/-encia: tolerar → tolerancia, existir → existencia\n\nThe suffix often determines the gender: -ción is always feminine, -miento always masculine."},
        {type:"teach",trg:"la tolerancia",src:"the tolerance",pos:"noun",gender:"f",phonetic:"la to-leh-RAN-thya",note:"From tolerar + -ancia. This suffix creates abstract quality nouns.",example:"A: ¿Cuál es el valor más importante en una sociedad?\nB: La tolerancia hacia las diferencias.\nA: ¿Y cómo se fomenta la tolerancia?\nB: A través de la educación y la convivencia.\nA: La tolerancia no significa aceptar todo, ¿verdad?\nB: Exacto, la tolerancia tiene sus límites razonables.",exampleSrc:"A: What is the most important value in a society?\nB: Tolerance of differences.\nA: And how is tolerance encouraged?\nB: Through education and coexistence.\nA: Tolerance doesn't mean accepting everything, right?\nB: Exactly, tolerance has its reasonable limits.",funFact:"Cognate with English 'tolerance'. Spanish and English share many Latin-derived words."},
        {type:"mc",q:"The verb investigar becomes the noun:",opts:["la investigación","el investigamiento","la investigaje","el investigatura"],ans:"la investigación",hint:"The most common suffix for -ar verbs ending in a process."},
        {type:"mc",q:"Which suffix turns conocer into a noun?",opts:["-ción","-miento","-aje","-ura"],ans:"-miento",hint:"This suffix is common with -er and -ir verbs."},
        {type:"fb",opts:["aprendizaje","aprender","aprendido","aprendiendo"],hint:"The noun form using the -aje suffix.",s:"El {1} de idiomas requiere práctica constante.",a:"aprendizaje"},
        {type:"mc",q:"La ___ del texto necesita mejorar.",opts:["estructura","estructurar","estructurado","estructurando"],ans:"estructura",hint:"The noun form with -ura suffix meaning arrangement or framework."},
        {type:"fb",opts:["tolerancia","tolerar","tolerante","tolerando"],hint:"The abstract noun formed with the -ancia suffix.",s:"La {1} hacia otras culturas es fundamental.",a:"tolerancia"},
        {type:"match",pairs:[
          {trg:"-ción",src:"investigación, educación"},
          {trg:"-miento",src:"conocimiento, sentimiento"},
          {trg:"-aje",src:"aprendizaje, almacenaje"},
          {trg:"-ura",src:"estructura, abertura"},
          {trg:"-ancia/-encia",src:"tolerancia, existencia"}
        ]},
        {type:"mc",q:"Which is always feminine?",opts:["Words ending in -miento","Words ending in -ción","Words ending in -aje","Words ending in -or"],ans:"Words ending in -ción",hint:"This suffix consistently takes the feminine article."},
        {type:"drag_fill",hint:"Research requires knowledge.",s:"La {1} científica requiere amplio {2} del tema.",blanks:{"1":"investigación","2":"conocimiento"},pool:["investigación","conocimiento","aprendizaje","estructura"]},
        {type:"fb",opts:["estructura","investigación","tolerancia","conocimiento"],hint:"This word refers to the organized framework of ideas.",s:"La {1} es la base de un buen argumento.",a:"estructura"},
        {type:"mc",q:"Existir becomes which noun?",opts:["la existancia","la existencia","el existimiento","la existición"],ans:"la existencia",hint:"The -encia suffix applies to verbs ending in -ir."},
        {type:"mc",q:"Which word is the nominalization of sentir?",opts:["el sentimiento","la sentición","el sentaje","la sentura"],ans:"el sentimiento",hint:"This verb uses the same suffix as conocimiento."}
  ]},
  {id:"esp27l3",title:"Lo + Adjetivo",icon:"💎",xp:15,board:true,steps:[
        {type:"intro",title:"Lo + Adjetivo",desc:"The neuter article lo transforms adjectives into abstract noun concepts. This is uniquely Spanish and extremely useful in formal writing.",goals:["Use lo + adjective for abstract concepts","Distinguish lo bueno, lo malo, lo importante","Apply lo + adjective in academic sentences"]},
        {type:"teach",trg:"lo importante",src:"the important thing / what matters",pos:"adj",gender:null,phonetic:"lo im-por-TAN-teh",note:"Lo + adjective creates an abstract concept. Very common.",example:"A: Hay muchos factores en este debate.\nB: Sí, pero lo importante es centrarse en los datos.\nA: ¿Y la opinión pública?\nB: Lo importante no es la opinión, sino la evidencia.\nA: Tienes razón. Lo importante es ser objetivos.\nB: Exacto, eso es lo fundamental.",exampleSrc:"A: There are many factors in this debate.\nB: Yes, but the important thing is to focus on the data.\nA: And public opinion?\nB: What matters is not opinion, but evidence.\nA: You're right. The important thing is to be objective.\nB: Exactly, that's what's fundamental.",funFact:"Spanish adjectives agree in gender and number. Most change -o/-a for gender and add -s for plural."},
        {type:"teach",trg:"lo difícil",src:"the difficult thing / what's hard",pos:"noun",gender:null,phonetic:"lo dee-FEE-thil",note:"Turns the adjective into an abstract noun concept.",example:"A: ¿Cómo va tu proyecto de investigación?\nB: Bien, pero lo difícil es encontrar participantes.\nA: ¿No puedes usar encuestas en línea?\nB: Lo difícil no es el método, sino la muestra.\nA: Entiendo. Lo difícil siempre es la parte práctica.\nB: Sí, lo difícil requiere más paciencia.",exampleSrc:"A: How is your research project going?\nB: Well, but the hard part is finding participants.\nA: Can't you use online surveys?\nB: The hard part isn't the method, but the sample.\nA: I see. The difficult thing is always the practical part.\nB: Yes, what's hard requires more patience.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"lo bueno",src:"the good thing / the good part",pos:"intj",gender:null,phonetic:"lo BWEH-no",note:"Lo bueno / lo malo are used to contrast positives and negatives.",example:"A: ¿Qué tal el nuevo sistema de evaluación?\nB: Tiene ventajas y desventajas.\nA: ¿Qué es lo bueno?\nB: Lo bueno es que es más objetivo.\nA: ¿Y lo malo?\nB: Lo malo es que requiere más tiempo de los profesores.",exampleSrc:"A: How is the new evaluation system?\nB: It has advantages and disadvantages.\nA: What's the good part?\nB: The good thing is that it's more objective.\nA: And the bad part?\nB: The bad thing is that it requires more teacher time.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"lo interesante",src:"the interesting thing / what's interesting",pos:"noun",gender:null,phonetic:"lo in-teh-reh-SAN-teh",note:"Lo interesante de + noun = what's interesting about something.",example:"A: Leí tu artículo sobre economía circular.\nB: ¿Qué te pareció lo más interesante?\nA: Lo interesante es la conexión con la sostenibilidad.\nB: Sí, lo interesante del tema es su aplicación práctica.\nA: ¿Vas a escribir más sobre eso?\nB: Sí, lo interesante siempre merece más análisis.",exampleSrc:"A: I read your article on circular economy.\nB: What did you find most interesting?\nA: The interesting thing is the connection with sustainability.\nB: Yes, what's interesting about the topic is its practical application.\nA: Are you going to write more about it?\nB: Yes, what's interesting always deserves more analysis.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Lo + Adjective: The Neuter Article",text:"Spanish has a neuter article lo (not el, not la) that turns adjectives into abstract nouns:\n\nlo bueno = the good thing, what's good\nlo malo = the bad thing, what's bad\nlo importante = what's important\nlo difícil = the hard part\nlo interesante = the interesting thing\n\nPattern: lo + adjective (masculine singular form)\nWith de: lo interesante del caso = the interesting thing about the case\nWith es que: lo bueno es que... = the good thing is that..."},
        {type:"teach",trg:"lo esencial",src:"the essential thing / what's essential",pos:"intj",gender:null,phonetic:"lo eh-sen-THYAL",note:"Very useful in academic contexts for prioritizing ideas.",example:"A: Tenemos poco tiempo para la presentación.\nB: Entonces centrémonos en lo esencial.\nA: ¿Qué consideras lo esencial?\nB: Lo esencial es el análisis de resultados.\nA: De acuerdo. Lo esencial primero.\nB: Siempre. Lo esencial no puede faltar.",exampleSrc:"A: We have little time for the presentation.\nB: Then let's focus on what's essential.\nA: What do you consider essential?\nB: The essential thing is the analysis of results.\nA: Agreed. The essentials first.\nB: Always. What's essential cannot be missing.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"Lo importante es ___ los datos correctamente.",opts:["analizar","analizando","analizado","análisis"],ans:"analizar",hint:"After lo importante es, use the infinitive verb form."},
        {type:"mc",q:"___ del estudio es su metodología innovadora.",opts:["Lo interesante","El interesante","La interesante","Los interesante"],ans:"Lo interesante",hint:"The neuter article creates an abstract concept from an adjective."},
        {type:"fb",opts:["malo","bueno","difícil","mala"],hint:"The opposite of lo bueno, expressing the negative aspect.",s:"Lo {1} es que no hay suficientes recursos.",a:"malo"},
        {type:"fb",opts:["interesante","difícil","esencial","importante"],hint:"This adjective describes something that captures your attention.",s:"Lo {1} del tema es su aplicación práctica.",a:"interesante"},
        {type:"mc",q:"Which sentence uses lo + adjective correctly?",opts:["Lo esencial es la colaboración","El esencial es la colaboración","La esencial es la colaboración","Los esencial es la colaboración"],ans:"Lo esencial es la colaboración",hint:"Abstract concepts use the neuter article, not masculine or feminine."},
        {type:"match",pairs:[
          {trg:"lo bueno",src:"the good thing"},
          {trg:"lo malo",src:"the bad thing"},
          {trg:"lo difícil",src:"the hard part"},
          {trg:"lo interesante",src:"the interesting thing"},
          {trg:"lo esencial",src:"the essential thing"}
        ]},
        {type:"drag_fill",hint:"Focus on what matters and what's essential.",s:"Lo {1} es centrarse en lo {2} y dejar lo demás para después.",blanks:{"1":"importante","2":"esencial"},pool:["importante","esencial","malo","interesante"]},
        {type:"mc",q:"Lo bueno ___ que el proyecto avanza.",opts:["es","está","ser","son"],ans:"es",hint:"With lo + adjective as subject, use the third person singular."},
        {type:"fb",opts:["esencial","bueno","interesante","malo"],hint:"Focus on the core, fundamental aspect.",s:"Centrémonos en lo {1} del problema.",a:"esencial"},
        {type:"mc",q:"Lo difícil de esta investigación ___ encontrar datos fiables.",opts:["es","son","está","están"],ans:"es",hint:"Lo + adjective creates a singular abstract noun. Which ser/estar form agrees with a singular subject?"},
        {type:"fb",opts:["difícil","bueno","importante","malo"],hint:"This adjective describes something that requires great effort.",s:"Lo {1} es mantener la calma en momentos de crisis.",a:"difícil"}
  ]},
  {id:"esp27l4",title:"Sustantivos Abstractos",icon:"🔬",xp:15,board:true,steps:[
        {type:"intro",title:"Sustantivos Abstractos",desc:"Master the abstract nouns that dominate academic and professional Spanish. These are the vocabulary of serious writing.",goals:["Use la implementación, el análisis, la evaluación","Form academic sentences with abstract nouns","Recognize abstract nouns in context"]},
        {type:"teach",trg:"la implementación",src:"the implementation",pos:"noun",gender:"f",phonetic:"la im-pleh-men-ta-THYON",note:"From implementar. Standard in business and academic texts.",example:"A: ¿Cuándo empezamos con el nuevo sistema?\nB: La implementación comenzará el próximo trimestre.\nA: ¿Quién supervisará la implementación?\nB: Un comité dedicado a la implementación del proyecto.\nA: ¿Y si surgen problemas durante la implementación?\nB: Tenemos un plan de contingencia.",exampleSrc:"A: When do we start with the new system?\nB: The implementation will begin next quarter.\nA: Who will supervise the implementation?\nB: A committee dedicated to the project's implementation.\nA: And if problems arise during implementation?\nB: We have a contingency plan.",funFact:"Cognate with English 'implementation'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el análisis",src:"the analysis",pos:"noun",gender:"m",phonetic:"el a-NA-lee-sees",note:"Plural: los análisis (no change). From analizar.",example:"A: ¿Has terminado el informe?\nB: Falta el análisis de los datos cuantitativos.\nA: ¿Qué tipo de análisis estás haciendo?\nB: Un análisis estadístico comparativo.\nA: ¿Y el análisis cualitativo?\nB: Ese análisis ya está completo.",exampleSrc:"A: Have you finished the report?\nB: The analysis of quantitative data is still missing.\nA: What kind of analysis are you doing?\nB: A comparative statistical analysis.\nA: And the qualitative analysis?\nB: That analysis is already complete.",funFact:"Cognate with English 'analysis'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"la evaluación",src:"the evaluation / assessment",pos:"noun",gender:"f",phonetic:"la eh-va-lwa-THYON",note:"From evaluar. Central to academic and professional work.",example:"A: ¿Cómo medimos el progreso?\nB: Con una evaluación periódica de los resultados.\nA: ¿Cada cuánto hacemos la evaluación?\nB: La evaluación trimestral es lo más efectivo.\nA: ¿Quién diseña los criterios de evaluación?\nB: El departamento de calidad.",exampleSrc:"A: How do we measure progress?\nB: With a periodic evaluation of the results.\nA: How often do we do the evaluation?\nB: Quarterly evaluation is most effective.\nA: Who designs the evaluation criteria?\nB: The quality department.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"la conclusión",src:"the conclusion",pos:"noun",gender:"f",phonetic:"la kon-kloo-SYON",note:"From concluir. Plural: las conclusiones.",example:"A: ¿Cuál es la conclusión de tu investigación?\nB: La conclusión principal es que se necesita más financiación.\nA: ¿Es una conclusión definitiva?\nB: No, la conclusión está sujeta a más datos.\nA: ¿Puedes resumir la conclusión?\nB: En resumen, la conclusión apunta a reformas necesarias.",exampleSrc:"A: What is the conclusion of your research?\nB: The main conclusion is that more funding is needed.\nA: Is it a definitive conclusion?\nB: No, the conclusion is subject to more data.\nA: Can you summarize the conclusion?\nB: In summary, the conclusion points to necessary reforms.",funFact:"Cognate with English 'conclusion'. Spanish and English share many Latin-derived words."},
        {type:"tip",title:"Abstract Nouns in Academic Writing",text:"Academic Spanish relies heavily on abstract nouns as sentence subjects:\n\nCasual: Analizamos los datos → hicimos esto\nAcademic: El análisis de los datos reveló que...\n\nCasual: Evaluamos el programa\nAcademic: La evaluación del programa demostró...\n\nKey pattern: la/el + abstract noun + de + complement\nla implementación del sistema\nel análisis de los resultados\nla evaluación del rendimiento"},
        {type:"teach",trg:"la contribución",src:"the contribution",pos:"noun",gender:"f",phonetic:"la kon-tree-boo-THYON",note:"From contribuir. Always feminine despite ending in -ción.",example:"A: ¿Cómo podemos reconocer su trabajo?\nB: Su contribución al proyecto ha sido fundamental.\nA: ¿En qué consistió la contribución exactamente?\nB: La contribución fue tanto teórica como práctica.\nA: Deberíamos documentar cada contribución.\nB: De acuerdo, la contribución de cada miembro importa.",exampleSrc:"A: How can we recognize their work?\nB: Their contribution to the project has been fundamental.\nA: What exactly was the contribution?\nB: The contribution was both theoretical and practical.\nA: We should document each contribution.\nB: Agreed, every member's contribution matters.",funFact:"Cognate with English 'contribution'. Spanish and English share many Latin-derived words."},
        {type:"mc",q:"El ___ de los datos reveló tendencias inesperadas.",opts:["análisis","analizar","analizado","analizando"],ans:"análisis",hint:"Use the noun form as the subject of the sentence."},
        {type:"mc",q:"La ___ del nuevo programa comenzará en septiembre.",opts:["implementación","implementar","implementado","implementando"],ans:"implementación",hint:"The noun form of implementar used as a subject."},
        {type:"fb",opts:["evaluación","conclusión","implementación","contribución"],hint:"The process of assessing or measuring performance.",s:"La {1} del rendimiento se hará cada trimestre.",a:"evaluación"},
        {type:"fb",opts:["conclusión","evaluación","análisis","contribución"],hint:"The final finding or result drawn from research.",s:"La {1} principal del estudio es clara.",a:"conclusión"},
        {type:"match",pairs:[
          {trg:"la implementación",src:"implementation"},
          {trg:"el análisis",src:"analysis"},
          {trg:"la evaluación",src:"evaluation"},
          {trg:"la conclusión",src:"conclusion"},
          {trg:"la contribución",src:"contribution"}
        ]},
        {type:"mc",q:"Which is the correct plural of el análisis?",opts:["los análisis","los analisises","las análisis","los analices"],ans:"los análisis",hint:"Words ending in -sis don't change in the plural."},
        {type:"drag_fill",hint:"Assessment and data review come first.",s:"La {1} del programa y el {2} de los resultados son prioritarios.",blanks:{"1":"evaluación","2":"análisis"},pool:["evaluación","análisis","contribución","conclusión"]},
        {type:"fb",opts:["contribución","conclusión","implementación","evaluación"],hint:"The noun describing what someone has given or added.",s:"Su {1} al campo de la medicina ha sido notable.",a:"contribución"},
        {type:"mc",q:"Academic style prefers which sentence structure?",opts:["El análisis reveló que...","Analizamos y vimos que...","Miramos los datos y...","Hicimos un análisis y..."],ans:"El análisis reveló que...",hint:"Formal writing uses abstract nouns as subjects, not personal verbs."},
        {type:"fb",opts:["implementación","evaluación","contribución","conclusión"],hint:"The noun form of putting a plan into action.",s:"La {1} del programa mejoró los resultados.",a:"implementación"},
        {type:"mc",q:"La evaluación ___ los resultados demuestra avances.",opts:["de","a","con","por"],ans:"de",hint:"Abstract nouns connect to their objects with this preposition."}
  ]},
  {id:"esp27l5",title:"Registro Formal",icon:"🎩",xp:15,board:true,steps:[
        {type:"intro",title:"Registro Formal",desc:"Learn to transform casual Spanish into academic register by using nominalization, impersonal constructions, and formal vocabulary.",goals:["Convert informal sentences to formal register","Recognize register differences","Choose appropriate register for context"]},
        {type:"teach",trg:"en primer lugar",src:"in the first place / firstly",pos:"intj",gender:null,phonetic:"en pree-MER loo-GAR",note:"Formal sequencing marker. More academic than primero.",example:"A: ¿Cómo organizo mi argumento?\nB: En primer lugar, presenta tu tesis central.\nA: ¿Y después?\nB: En segundo lugar, aporta la evidencia.\nA: ¿Y en tercer lugar?\nB: En tercer lugar, discute las implicaciones.",exampleSrc:"A: How do I organize my argument?\nB: In the first place, present your central thesis.\nA: And then?\nB: In the second place, provide the evidence.\nA: And thirdly?\nB: In the third place, discuss the implications.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"cabe destacar que",src:"it is worth noting that",pos:"intj",gender:null,phonetic:"KA-beh des-ta-KAR keh",note:"Very formal. Used to introduce important observations.",example:"A: ¿Algo más sobre los resultados?\nB: Cabe destacar que la muestra fue limitada.\nA: ¿Eso afecta las conclusiones?\nB: Cabe destacar que no invalida los hallazgos.\nA: Entiendo.\nB: Cabe destacar también que necesitamos más datos.",exampleSrc:"A: Anything else about the results?\nB: It is worth noting that the sample was limited.\nA: Does that affect the conclusions?\nB: It is worth noting that it doesn't invalidate the findings.\nA: I understand.\nB: It is also worth noting that we need more data.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"dicho de otro modo",src:"in other words / put differently",pos:"conj",gender:null,phonetic:"DEE-cho deh OH-tro MO-do",note:"Academic connector for restating ideas more clearly.",example:"A: No entiendo la hipótesis.\nB: Dicho de otro modo, proponemos que el factor clave es la educación.\nA: ¿Puedes simplificarlo más?\nB: Dicho de otro modo, la educación determina el resultado.\nA: Ahora sí entiendo.\nB: Bien, dicho de otro modo siempre ayuda a clarificar.",exampleSrc:"A: I don't understand the hypothesis.\nB: In other words, we propose that the key factor is education.\nA: Can you simplify it more?\nB: Put differently, education determines the outcome.\nA: Now I understand.\nB: Good, rephrasing always helps to clarify.",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"teach",trg:"a modo de conclusión",src:"by way of conclusion",pos:"intj",gender:null,phonetic:"a MO-do deh kon-kloo-SYON",note:"Formal way to introduce closing remarks.",example:"A: ¿Cómo termino la presentación?\nB: A modo de conclusión, resume los puntos clave.\nA: ¿Algo más formal que 'para terminar'?\nB: Sí, a modo de conclusión es perfecto para el ámbito académico.\nA: ¿Y qué digo después?\nB: A modo de conclusión, sintetiza todo en dos o tres frases.",exampleSrc:"A: How do I end the presentation?\nB: By way of conclusion, summarize the key points.\nA: Something more formal than 'to finish'?\nB: Yes, by way of conclusion is perfect for academic settings.\nA: And what do I say after?\nB: By way of conclusion, synthesize everything in two or three sentences.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Informal vs Formal Register",text:"Informal → Formal transformations:\n\nPrimero... → En primer lugar...\nPara terminar → A modo de conclusión\nTambién hay que decir → Cabe destacar que\nO sea → Dicho de otro modo\nCreo que → Se considera que\nTenemos que → Es necesario / Resulta imprescindible\n\nFormal register avoids:\n1. First person (yo creo → se considera)\n2. Colloquial connectors (o sea → es decir)\n3. Simple verbs (hacer → realizar, llevar a cabo)"},
        {type:"teach",trg:"resulta imprescindible",src:"it is essential / it proves indispensable",pos:"intj",gender:null,phonetic:"reh-SOOL-ta im-pres-thin-DEE-bleh",note:"More formal than es necesario. Used for strong recommendations.",example:"A: ¿Qué recomendaciones incluimos?\nB: Resulta imprescindible aumentar la financiación.\nA: ¿Es realmente tan urgente?\nB: Resulta imprescindible si queremos avanzar.\nA: ¿Algo más?\nB: También resulta imprescindible mejorar la formación.",exampleSrc:"A: What recommendations do we include?\nB: It is essential to increase funding.\nA: Is it really that urgent?\nB: It is indispensable if we want to progress.\nA: Anything else?\nB: It is also essential to improve training.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"Which is the most formal way to say 'firstly'?",opts:["Primero","En primer lugar","Para empezar","Uno"],ans:"En primer lugar",hint:"Academic writing uses a longer, more structured sequencing phrase."},
        {type:"mc",q:"'Cabe destacar que' means:",opts:["It is worth noting that","It is possible that","In conclusion","First of all"],ans:"It is worth noting that",hint:"This phrase introduces an important observation."},
        {type:"fb",opts:["Dicho","Hecho","Puesto","Dado"],hint:"This word means 'said' or 'put' when rephrasing.",s:"{1} de otro modo, los resultados son positivos.",a:"Dicho"},
        {type:"fb",opts:["modo","forma","tipo","final"],hint:"This word means 'way' or 'manner' in this formal expression.",s:"A {1} de conclusión, los datos confirman la hipótesis.",a:"modo"},
        {type:"mc",q:"The formal equivalent of 'Creo que es importante' is:",opts:["Resulta imprescindible","Yo pienso que sí","Me parece importante","Creo que hay que"],ans:"Resulta imprescindible",hint:"Formal register avoids first person and uses impersonal structures."},
        {type:"match",pairs:[
          {trg:"en primer lugar",src:"in the first place"},
          {trg:"cabe destacar que",src:"it is worth noting that"},
          {trg:"dicho de otro modo",src:"in other words"},
          {trg:"a modo de conclusión",src:"by way of conclusion"},
          {trg:"resulta imprescindible",src:"it is essential"}
        ]},
        {type:"drag_fill",hint:"It is worth noting + it is essential.",s:"{1} destacar que los resultados {2} imprescindible analizarlos con cuidado.",blanks:{"1":"Cabe","2":"resulta"},pool:["Cabe","resulta","dicho","modo"]},
        {type:"mc",q:"Which register is appropriate for an academic essay?",opts:["O sea, los datos molan","Los datos son buenos, creo yo","El análisis de los datos revela tendencias significativas","Miramos los datos y son guay"],ans:"El análisis de los datos revela tendencias significativas",hint:"Academic register uses nominalization and avoids colloquialisms."},
        {type:"fb",opts:["primer","primero","primera","uno"],hint:"The ordinal form used before a masculine noun in this expression.",s:"En {1} lugar, presentaremos el marco teórico.",a:"primer"},
        {type:"mc",q:"Formal writing avoids which of the following?",opts:["Abstract nouns","First person singular","Impersonal constructions","Complex connectors"],ans:"First person singular",hint:"Academic texts prefer im___al structures over yo creo, yo pienso."},
        {type:"fb",opts:["Cabe","Hay","Es","Puede"],hint:"This verb means it is fitting or appropriate to mention.",s:"{1} destacar que los resultados son preliminares.",a:"Cabe"}
  ]},
  {id:"esp27l6",title:"La Pasiva Académica",icon:"📰",xp:15,board:true,steps:[
        {type:"intro",title:"La Pasiva Académica",desc:"Review and deepen passive constructions for academic writing: se + verb and ser + past participle in formal contexts.",goals:["Use se pasiva in academic sentences","Form ser + participle constructions","Choose the right passive for formal writing"]},
        {type:"teach",trg:"se considera que",src:"it is considered that",pos:"intj",gender:null,phonetic:"seh kon-see-DEH-ra keh",note:"Se + third person singular. Very common in academic writing.",example:"A: ¿Qué dice la literatura sobre este tema?\nB: Se considera que la educación bilingüe tiene ventajas.\nA: ¿Quién lo considera?\nB: Se considera ampliamente entre los investigadores.\nA: ¿Y hay evidencia?\nB: Sí, se considera demostrado por múltiples estudios.",exampleSrc:"A: What does the literature say about this topic?\nB: It is considered that bilingual education has advantages.\nA: Who considers it?\nB: It is widely considered among researchers.\nA: And is there evidence?\nB: Yes, it is considered proven by multiple studies.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"se ha demostrado que",src:"it has been demonstrated that",pos:"intj",gender:null,phonetic:"seh ah deh-mos-TRA-do keh",note:"Se + ha + past participle. Perfect tense passive for established facts.",example:"A: ¿Puedes justificar esta afirmación?\nB: Se ha demostrado que el ejercicio mejora la memoria.\nA: ¿En qué estudios?\nB: Se ha demostrado en investigaciones recientes.\nA: ¿Es un consenso?\nB: Sí, se ha demostrado repetidamente.",exampleSrc:"A: Can you justify this claim?\nB: It has been demonstrated that exercise improves memory.\nA: In which studies?\nB: It has been demonstrated in recent research.\nA: Is it a consensus?\nB: Yes, it has been demonstrated repeatedly.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"fue publicado/a",src:"was published",pos:"num",gender:null,phonetic:"fweh poo-blee-KA-do",note:"Ser + past participle. The participle agrees in gender/number.",example:"A: ¿Cuándo salió ese artículo?\nB: Fue publicado en la Revista de Educación en 2024.\nA: ¿Y el libro?\nB: El libro fue publicado un año después.\nA: ¿Dónde fue publicado?\nB: Fue publicado por una editorial universitaria.",exampleSrc:"A: When did that article come out?\nB: It was published in the Education Journal in 2024.\nA: And the book?\nB: The book was published a year later.\nA: Where was it published?\nB: It was published by a university press.",funFact:"Spanish numbers are straightforward. Gender only matters for 'uno/una' and hundreds (doscientos/doscientas)."},
        {type:"teach",trg:"se recomienda",src:"it is recommended",pos:"intj",gender:null,phonetic:"seh reh-ko-MYEN-da",note:"Impersonal se passive. No agent specified. Very academic.",example:"A: ¿Qué debemos hacer con los datos?\nB: Se recomienda verificarlos con una segunda fuente.\nA: ¿Y sobre la metodología?\nB: Se recomienda usar un enfoque mixto.\nA: ¿Quién lo recomienda?\nB: Se recomienda en las guías de investigación.",exampleSrc:"A: What should we do with the data?\nB: It is recommended to verify them with a second source.\nA: And about methodology?\nB: A mixed approach is recommended.\nA: Who recommends it?\nB: It is recommended in research guidelines.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Two Passive Voices in Academic Spanish",text:"Spanish has two passive constructions:\n\n1. Se pasiva (more common in academic Spanish):\nSe considera que... (It is considered that...)\nSe ha demostrado que... (It has been shown that...)\nSe recomienda... (It is recommended...)\n\n2. Ser + past participle (for specific events):\nFue publicado en 2024 (It was published in 2024)\nFue realizado por el equipo (It was carried out by the team)\n\nSe pasiva: general truths, no agent\nSer + participle: specific events, agent possible with 'por'"},
        {type:"teach",trg:"se observa que",src:"it is observed that",pos:"intj",gender:null,phonetic:"seh ob-SER-va keh",note:"Common for presenting research findings objectively.",example:"A: ¿Qué muestran los gráficos?\nB: Se observa que hay una tendencia al alza.\nA: ¿Es significativa?\nB: Se observa que la diferencia es estadísticamente relevante.\nA: Interesante.\nB: Sí, se observa un patrón claro en los datos.",exampleSrc:"A: What do the graphs show?\nB: It is observed that there is an upward trend.\nA: Is it significant?\nB: It is observed that the difference is statistically relevant.\nA: Interesting.\nB: Yes, a clear pattern is observed in the data.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"___ que la educación temprana mejora los resultados.",opts:["Se ha demostrado","Ha demostrado","Demostró se","Se demostrado ha"],ans:"Se ha demostrado",hint:"Se + auxiliary ha + past participle for established findings."},
        {type:"mc",q:"El artículo ___ en una revista internacional.",opts:["fue publicado","se publicó","publicó fue","fue publicando"],ans:"fue publicado",hint:"Use ser + past participle for a specific publication event."},
        {type:"fb",opts:["recomienda","recomiendan","recomiende","recomendó"],hint:"Impersonal se uses third person singular for recommendations.",s:"Se {1} que los estudiantes lean el texto completo.",a:"recomienda"},
        {type:"fb",opts:["observa","observan","observó","observando"],hint:"Impersonal se in present tense. The clause after que describes a current finding.",s:"Se {1} que hay una correlación entre las variables.",a:"observa"},
        {type:"mc",q:"Which is the se pasiva form of 'consideran esto importante'?",opts:["Se considera importante","Esto se consideran importante","Se consideran importante esto","Importante se considera"],ans:"Se considera importante",hint:"Se + third person singular for impersonal passive."},
        {type:"match",pairs:[
          {trg:"se considera que",src:"it is considered that"},
          {trg:"se ha demostrado que",src:"it has been shown that"},
          {trg:"fue publicado",src:"was published"},
          {trg:"se recomienda",src:"it is recommended"},
          {trg:"se observa que",src:"it is observed that"}
        ]},
        {type:"drag_fill",hint:"It has been shown... and is recommended.",s:"Se {1} que el método es eficaz y se {2} su uso.",blanks:{"1":"ha demostrado","2":"recomienda"},pool:["ha demostrado","recomienda","fue publicado","observa"]},
        {type:"mc",q:"In academic writing, which passive is more common?",opts:["Se pasiva","Ser + participle","Both equally","Neither"],ans:"Se pasiva",hint:"Academic Spanish prefers the construction without a stated agent."},
        {type:"fb",opts:["fue","se","ha","es"],hint:"For a specific completed event with an agent, use ser + participle.",s:"El estudio {1} realizado por un equipo internacional.",a:"fue"},
        {type:"mc",q:"Se observa que los datos ___ una correlación fuerte.",opts:["muestran","muestren","mostraron","mostrarán"],ans:"muestran",hint:"After se observa que, present indicative describes current findings."},
        {type:"fb",opts:["considera","consideran","considere","consideró"],hint:"Impersonal se uses third person singular for general beliefs.",s:"Se {1} que el nuevo método es más eficiente.",a:"considera"}
  ]},
  {id:"esp27l7",title:"Expresiones Impersonales",icon:"🏛️",xp:15,board:true,steps:[
        {type:"intro",title:"Expresiones Impersonales",desc:"Master impersonal expressions that are the hallmark of formal and academic Spanish writing.",goals:["Use es necesario que + subjuntivo","Use cabe + infinitivo constructions","Apply conviene que and resulta que patterns"]},
        {type:"teach",trg:"es necesario que",src:"it is necessary that",pos:"intj",gender:null,phonetic:"es neh-theh-SA-ryo keh",note:"Always followed by subjuntivo. Core impersonal expression.",example:"A: ¿Cómo mejoramos la investigación?\nB: Es necesario que ampliemos la muestra.\nA: ¿Algo más?\nB: Es necesario que revisemos la metodología.\nA: ¿Y los plazos?\nB: Es necesario que los cumplamos estrictamente.",exampleSrc:"A: How do we improve the research?\nB: It is necessary that we expand the sample.\nA: Anything else?\nB: It is necessary that we review the methodology.\nA: And the deadlines?\nB: It is necessary that we meet them strictly.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"conviene que",src:"it is advisable that",pos:"intj",gender:null,phonetic:"kon-BYEH-neh keh",note:"Softer than es necesario. Followed by subjuntivo.",example:"A: ¿Qué formato uso para el ensayo?\nB: Conviene que sigas las normas APA.\nA: ¿Y sobre las citas?\nB: Conviene que cites al menos diez fuentes.\nA: ¿Conviene que incluya gráficos?\nB: Sí, conviene que los datos sean visuales.",exampleSrc:"A: What format do I use for the essay?\nB: It is advisable that you follow APA guidelines.\nA: And about citations?\nB: It is advisable that you cite at least ten sources.\nA: Is it advisable to include graphics?\nB: Yes, it is advisable that the data be visual.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"cabe señalar que",src:"it should be pointed out that",pos:"intj",gender:null,phonetic:"KA-beh seh-nya-LAR keh",note:"Variation of cabe destacar. Used for limitations and caveats.",example:"A: ¿Hay limitaciones en el estudio?\nB: Cabe señalar que la muestra fue pequeña.\nA: ¿Eso invalida los resultados?\nB: No, pero cabe señalar que son preliminares.\nA: ¿Algo más que señalar?\nB: Cabe señalar que se necesita más investigación.",exampleSrc:"A: Are there limitations in the study?\nB: It should be pointed out that the sample was small.\nA: Does that invalidate the results?\nB: No, but it should be pointed out that they are preliminary.\nA: Anything else to point out?\nB: It should be pointed out that more research is needed.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"resulta evidente que",src:"it is evident that",pos:"intj",gender:null,phonetic:"reh-SOOL-ta eh-vee-DEN-teh keh",note:"Strong assertion. Use when evidence clearly supports the claim.",example:"A: ¿Qué conclusiones sacas de los datos?\nB: Resulta evidente que el programa funciona.\nA: ¿Hay datos que lo respalden?\nB: Sí, resulta evidente a partir de las estadísticas.\nA: ¿Los críticos estarían de acuerdo?\nB: Resulta evidente para cualquier observador objetivo.",exampleSrc:"A: What conclusions do you draw from the data?\nB: It is evident that the program works.\nA: Is there data to support it?\nB: Yes, it is evident from the statistics.\nA: Would critics agree?\nB: It is evident to any objective observer.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Impersonal Expressions in Academic Writing",text:"These structures remove the personal subject, making claims sound objective:\n\nWith subjuntivo:\nes necesario que + subjuntivo\nconviene que + subjuntivo\nes imprescindible que + subjuntivo\n\nWith indicativo:\nresulta evidente que + indicativo\nse ha demostrado que + indicativo\n\nWith infinitivo:\ncabe señalar / cabe destacar + que\nconviene + infinitivo\n\nKey: Subjuntivo for recommendations/obligations.\nIndicativo for presenting established facts."},
        {type:"teach",trg:"es imprescindible que",src:"it is essential that",pos:"intj",gender:null,phonetic:"es im-pres-thin-DEE-bleh keh",note:"Stronger than es necesario. For urgent academic recommendations.",example:"A: ¿Qué cambios proponéis?\nB: Es imprescindible que se aumente el presupuesto.\nA: ¿Y en cuanto al personal?\nB: Es imprescindible que se contrate más personal.\nA: ¿Hay otras prioridades?\nB: Es imprescindible que se modernice la infraestructura.",exampleSrc:"A: What changes do you propose?\nB: It is essential that the budget be increased.\nA: And regarding staff?\nB: It is essential that more staff be hired.\nA: Are there other priorities?\nB: It is essential that the infrastructure be modernized.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"Es necesario que los investigadores ___ los datos.",opts:["verifiquen","verifican","verificar","verificaron"],ans:"verifiquen",hint:"After es necesario que, the verb must be in subjuntive mood."},
        {type:"mc",q:"'Cabe señalar que' is best translated as:",opts:["It should be pointed out that","It is necessary that","In conclusion","We believe that"],ans:"It should be pointed out that",hint:"This cabe expression introduces observations or caveats."},
        {type:"fb",opts:["Conviene","Cabe","Resulta","Dicho"],hint:"This impersonal verb means 'it is advisable'.",s:"{1} que los participantes firmen el consentimiento.",a:"Conviene"},
        {type:"fb",opts:["evidente","necesario","imprescindible","conveniente"],hint:"This adjective means the evidence clearly shows something.",s:"Resulta {1} que el método es efectivo.",a:"evidente"},
        {type:"mc",q:"Which expression is followed by subjuntivo?",opts:["Resulta evidente que","Se ha demostrado que","Es imprescindible que","Cabe señalar que"],ans:"Es imprescindible que",hint:"Expressions of obligation or necessity trigger the subjunctive."},
        {type:"match",pairs:[
          {trg:"es necesario que",src:"it is necessary that"},
          {trg:"conviene que",src:"it is advisable that"},
          {trg:"cabe señalar que",src:"it should be pointed out that"},
          {trg:"resulta evidente que",src:"it is evident that"},
          {trg:"es imprescindible que",src:"it is essential that"}
        ]},
        {type:"drag_fill",hint:"It is essential + it should be pointed out.",s:"Es {1} que se revise la ley y {2} señalar que urge.",blanks:{"1":"imprescindible","2":"cabe"},pool:["imprescindible","cabe","evidente","conviene"]},
        {type:"mc",q:"Resulta evidente que + ___",opts:["indicativo","subjuntivo","infinitivo","gerundio"],ans:"indicativo",hint:"When stating an evident fact, the verb is in the indicative mood."},
        {type:"fb",opts:["necesario","evidente","señalar","dicho"],hint:"This impersonal expression states an obligation.",s:"Es {1} que todos colaboren en el proyecto.",a:"necesario"},
        {type:"mc",q:"Conviene que los alumnos ___ las instrucciones.",opts:["lean","leen","leer","leyeron"],ans:"lean",hint:"After conviene que, the verb takes the subjunctive form."},
        {type:"fb",opts:["señalar","destacar","decir","ver"],hint:"This infinitive means to point out or indicate.",s:"Cabe {1} que la muestra fue limitada.",a:"señalar"}
  ]},
  {id:"esp27l8",title:"El Párrafo Formal",icon:"✍️",xp:15,board:true,steps:[
        {type:"intro",title:"El Párrafo Formal",desc:"Combine all U27 techniques: nominalization, lo + adjective, passive voice, impersonal expressions, and formal connectors to write academic paragraphs.",goals:["Combine nominalization with passive constructions","Write complete formal sentences","Transform informal text into academic register"]},
        {type:"teach",trg:"a partir de",src:"based on / starting from",pos:"conj",gender:null,phonetic:"a par-TEER deh",note:"Very common academic connector for citing evidence sources.",example:"A: ¿Cómo llegaste a esa conclusión?\nB: A partir de los datos recogidos en la encuesta.\nA: ¿Y qué encontraste?\nB: A partir de los resultados, se observa una mejora.\nA: ¿Podemos generalizar a partir de esta muestra?\nB: A partir de estudios similares, sí podemos.",exampleSrc:"A: How did you reach that conclusion?\nB: Based on the data collected in the survey.\nA: And what did you find?\nB: Based on the results, an improvement is observed.\nA: Can we generalize from this sample?\nB: Based on similar studies, yes we can.",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"teach",trg:"en lo que respecta a",src:"with regard to / as regards",pos:"intj",gender:null,phonetic:"en lo keh rres-PEK-ta a",note:"Formal topic-introduction phrase. Very academic.",example:"A: ¿Qué dice el informe sobre la financiación?\nB: En lo que respecta a la financiación, se necesita más inversión.\nA: ¿Y en lo que respecta a los plazos?\nB: En lo que respecta a los plazos, son realistas.\nA: ¿Y el personal?\nB: En lo que respecta al personal, es suficiente.",exampleSrc:"A: What does the report say about funding?\nB: With regard to funding, more investment is needed.\nA: And as regards the deadlines?\nB: As regards the deadlines, they are realistic.\nA: And the staff?\nB: With regard to staff, it is sufficient.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"de acuerdo con",src:"according to",pos:"noun",gender:null,phonetic:"deh a-KWER-do kon",note:"Formal citation marker. Used to reference sources.",example:"A: ¿Qué dicen los expertos?\nB: De acuerdo con el informe, los resultados son prometedores.\nA: ¿Y de acuerdo con otros estudios?\nB: De acuerdo con la investigación previa, se confirman las hipótesis.\nA: Es convincente.\nB: De acuerdo con toda la evidencia disponible, sí.",exampleSrc:"A: What do the experts say?\nB: According to the report, the results are promising.\nA: And according to other studies?\nB: According to previous research, the hypotheses are confirmed.\nA: It's convincing.\nB: According to all available evidence, yes.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"en definitiva",src:"in short / ultimately",pos:"conj",gender:null,phonetic:"en deh-fee-nee-TEE-va",note:"Formal summary connector. Used before final statements.",example:"A: Entonces, ¿cuál es tu veredicto?\nB: En definitiva, el proyecto es viable.\nA: ¿Podemos proceder?\nB: En definitiva, sí, con algunas modificaciones.\nA: ¿Cuáles serían?\nB: En definitiva, hay que ajustar el presupuesto y los plazos.",exampleSrc:"A: So, what is your verdict?\nB: In short, the project is viable.\nA: Can we proceed?\nB: Ultimately, yes, with some modifications.\nA: What would those be?\nB: In short, the budget and deadlines need adjusting.",funFact:"Spanish conjunctions are essential for building longer sentences and expressing complex ideas."},
        {type:"tip",title:"Building a Formal Paragraph",text:"A complete formal paragraph combines:\n\n1. Topic sentence with nominalization:\n   La implementación del programa ha generado...\n\n2. Evidence with passive/impersonal:\n   Se ha demostrado que... / De acuerdo con...\n\n3. Analysis with lo + adjective:\n   Lo importante es que... / Lo relevante de estos datos...\n\n4. Connectors for cohesion:\n   En primer lugar... En lo que respecta a...\n\n5. Conclusion:\n   A modo de conclusión... / En definitiva..."},
        {type:"mc",q:"___ los datos del estudio, la hipótesis se confirma.",opts:["De acuerdo con","De acuerdo a","Según con","Acuerdo de"],ans:"De acuerdo con",hint:"The correct preposition after de ___ is con."},
        {type:"mc",q:"Which phrase introduces a new topic formally?",opts:["En lo que respecta a","Sobre el tema de","Hablando de","Bueno, pues"],ans:"En lo que respecta a",hint:"The most formal option for introducing a topic in academic writing."},
        {type:"fb",opts:["partir","acuerdo","modo","lo"],hint:"This phrase means 'based on' or 'starting from'.",s:"A {1} de los resultados, se observa una tendencia positiva.",a:"partir"},
        {type:"fb",opts:["definitiva","conclusión","resumen","total"],hint:"This word means 'ultimately' or 'in short'.",s:"En {1}, los datos confirman nuestra hipótesis.",a:"definitiva"},
        {type:"mc",q:"Choose the best academic sentence:",opts:["La implementación del programa se ha realizado con éxito","Hicimos el programa y funcionó bien","El programa lo pusimos y va genial","Implementamos la cosa esa"],ans:"La implementación del programa se ha realizado con éxito",hint:"Academic register uses nominalization and passive constructions."},
        {type:"match",pairs:[{trg:"a partir de",src:"based on"},{trg:"en lo que respecta a",src:"with regard to"},{trg:"de acuerdo con",src:"according to"},{trg:"en definitiva",src:"in short / ultimately"}]},
        {type:"drag_fill",hint:"According to the report, the implementation was successful.",s:"De {1} con el informe, la {2} del sistema ha sido exitosa.",blanks:{"1":"acuerdo","2":"implementación"},pool:["acuerdo","implementación","definitiva","partir"]},
        {type:"mc",q:"Transform: 'Creemos que hay que cambiar la ley'",opts:["Se considera necesario modificar la legislación","Creemos que la ley tiene que cambiar","La ley hay que cambiarla, creemos","Pensamos en cambiar la ley"],ans:"Se considera necesario modificar la legislación",hint:"Remove first person, use se pasiva, use formal vocabulary."},
        {type:"fb",opts:["respecta","refiere","toca","concierne"],hint:"This verb means 'concerns' in the formal topic phrase.",s:"En lo que {1} a la metodología, se siguieron las normas internacionales.",a:"respecta"},
        {type:"mc",q:"Which combines nominalization + impersonal correctly?",opts:["Se ha demostrado la importancia de la educación","La educación es importante, se ha visto","Demostrado se ha que educar importa","Es importante la educación que se demuestra"],ans:"Se ha demostrado la importancia de la educación",hint:"Se pasiva + abstract noun = perfect academic construction."},
        {type:"drag_fill",hint:"In short, based on the evidence...",s:"En {1}, a {2} de la evidencia, la contribución de este estudio es significativa.",blanks:{"1":"definitiva","2":"partir"},pool:["definitiva","partir","acuerdo","modo"]},
        {type:"mc",q:"Which is the best academic opening for a paragraph?",opts:["La implementación del programa reveló que...","Bueno, pues hicimos el programa y...","Hicimos una cosa interesante que...","Yo creo que el programa fue bien."],ans:"La implementación del programa reveló que...",hint:"Academic register uses nominalization as subject, not first person."}
  ]}
]};
